const row = $node["Loop Over Items"].json;
const errors = [];

if (!row.email || row.email.trim() === '') {
  errors.push('Missing email address');
} else {
  const email = row.email.trim().toLowerCase();
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!emailRegex.test(email)) {
    errors.push('Invalid email format');
  }
}

return {
  email: (row.email || '').trim().toLowerCase(),
  email_valid: errors.length === 0,
  errors
};

const fileFormat = $node["Webhook"].json.body.file_format || 'csv';
const fileContent = $node["Download File"].data.body;

let data = [];

if (fileFormat === 'csv') {
  // Parse CSV - simple comma-separated parser
  const lines = fileContent.split('\n').filter(line => line.trim());
  const headers = lines[0].split(',').map(h => h.trim());

  for (let i = 1; i < lines.length; i++) {
    const values = lines[i].split(',').map(v => v.trim());
    const row = {};
    headers.forEach((header, idx) => {
      row[header] = values[idx] || '';
    });
    data.push(row);
  }
}

if (fileFormat === 'json') {
  const parsed = JSON.parse(fileContent);
  data = Array.isArray(parsed) ? parsed : (parsed.employees || parsed.data || []);
}

return { data };

const row = $node["Loop Over Items"].json;
const prevErrors = $node["Validate Email"].json.errors || [];
const errors = [...prevErrors];

if (!row.full_name || row.full_name.trim() === '') {
  errors.push('Missing full name');
}

if (!row.role || row.role.trim() === '') {
  errors.push('Missing role');
}

if (!row.department || row.department.trim() === '') {
  errors.push('Missing department');
}

if (!row.phone || row.phone.trim() === '') {
  errors.push('Missing phone number');
}

if (!row.start_date || row.start_date.trim() === '') {
  errors.push('Missing start date');
}

return {
  required_fields_valid: errors.length === prevErrors.length,
  errors
};

const row = $node["Loop Over Items"].json;

function toTitleCase(str) {
  return str
    .trim()
    .split(' ')
    .map(word => word.charAt(0).toUpperCase() + word.slice(1).toLowerCase())
    .join(' ');
}

return {
  email: row.email.trim().toLowerCase(),
  full_name: toTitleCase(row.full_name),
  full_name_original: row.full_name
};

const row = $node["Loop Over Items"].json;
const phone = row.phone || '';

function normalizePhone(phoneString) {
  if (!phoneString || phoneString.trim() === '') return null;

  let cleaned = phoneString.trim().replace(/[^\d+]/g, '');

  if (!cleaned.startsWith('+')) {
    cleaned = '+1' + cleaned;
  }

  const digitCount = cleaned.replace(/\D/g, '').length;
  if (digitCount < 7 || digitCount > 15) {
    return null; // Invalid
  }

  return cleaned;
}

return {
  phone: normalizePhone(phone),
  phone_original: phone
};

const row = $node["Loop Over Items"].json;
const dateString = row.start_date || '';

function parseDate(str) {
  if (!str) return null;

  const s = str.trim();
  let date = null;

  // MM/DD/YYYY
  let match = s.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);
  if (match) {
    date = new Date(match[3], parseInt(match[1]) - 1, match[2]);
  }

  // YYYY-MM-DD
  match = s.match(/^(\d{4})-(\d{1,2})-(\d{1,2})$/);
  if (match) {
    date = new Date(match[1], parseInt(match[2]) - 1, match[3]);
  }

  // DD-MM-YYYY or MM-DD-YYYY
  match = s.match(/^(\d{1,2})-(\d{1,2})-(\d{4})$/);
  if (match) {
    const day = parseInt(match[1]);
    const month = parseInt(match[2]);
    if (day > 12) {
      date = new Date(match[3], month - 1, day);
    } else {
      date = new Date(match[3], day - 1, month);
    }
  }

  // ✅ NEW: Month DD YYYY or Month DD, YYYY (e.g. "Jan 20 2024", "March 1 2024", "Feb 15, 2024")
  match = s.match(/^([A-Za-z]+)\s+(\d{1,2}),?\s+(\d{4})$/);
  if (match) {
    const parsed = new Date(`${match[1]} ${match[2]} ${match[3]}`);
    if (!isNaN(parsed)) date = parsed;
  }

  // ✅ NEW: YYYY/MM/DD (e.g. "2024/03/05")
  match = s.match(/^(\d{4})\/(\d{1,2})\/(\d{1,2})$/);
  if (match) {
    date = new Date(match[1], parseInt(match[2]) - 1, match[3]);
  }

  // ✅ NEW: YYYY.MM.DD (e.g. "2024.02.01")
  match = s.match(/^(\d{4})\.(\d{1,2})\.(\d{1,2})$/);
  if (match) {
    date = new Date(match[1], parseInt(match[2]) - 1, match[3]);
  }

  if (date && !isNaN(date)) {
    return date.toISOString().split('T')[0];
  }

  return null;
}

return {
  start_date: parseDate(dateString),
  start_date_original: dateString
};

const row = $node["Loop Over Items"].json;

const roleMapping = {
  'manager': 'MANAGER',
  'mgr': 'MANAGER',
  'mngr': 'MANAGER',
  'engineer': 'ENGINEER',
  'eng': 'ENGINEER',
  'developer': 'ENGINEER',
  'dev': 'ENGINEER',
  'support': 'SUPPORT',
  'support rep': 'SUPPORT',
  'customer success': 'SUPPORT',
  'sales': 'SALES',
  'sales rep': 'SALES',
  'account manager': 'SALES',
  'hr': 'HR',
  'human resources': 'HR',
  'qa': 'QA',
  'quality assurance': 'QA',
  'product manager': 'PRODUCT_MANAGER',
  'product': 'PRODUCT_MANAGER',
  'pm': 'PRODUCT_MANAGER'
};

const inputRole = (row.role || '').trim().toLowerCase();
const mappedRole = roleMapping[inputRole];

return {
  role: mappedRole || null,
  role_original: row.role,
  role_valid: !!mappedRole
};

const row = $node["Loop Over Items"].json;

const departmentDefaults = {
  'MANAGER': 'Administration',
  'ENGINEER': 'Engineering',
  'SUPPORT': 'Customer Success',
  'SALES': 'Sales',
  'HR': 'Human Resources',
  'QA': 'Quality Assurance',
  'PRODUCT_MANAGER': 'Product'
};

let department = (row.department || '').trim();

if (department === '') {
  department = departmentDefaults[row.role] || 'General';
}

return {
  department
};

function generateTempPassword() {
  const uppercase = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ';
  const lowercase = 'abcdefghijklmnopqrstuvwxyz';
  const numbers = '0123456789';
  const symbols = '!@#$%^&*';

  let password = '';
  password += uppercase[Math.floor(Math.random() * uppercase.length)];
  password += lowercase[Math.floor(Math.random() * lowercase.length)];
  password += numbers[Math.floor(Math.random() * numbers.length)];
  password += symbols[Math.floor(Math.random() * symbols.length)];

  const all = uppercase + lowercase + numbers;
  for (let i = 0; i < 4; i++) {
    password += all[Math.floor(Math.random() * all.length)];
  }

  return password.split('').sort(() => 0.5 - Math.random()).join('');
}

return {
  temp_password: generateTempPassword()
};

