const email = $node['Normalize Email & Name'].json.email;
const full_name = $node['Normalize Email & Name'].json.full_name;
const existingUser = $node['Check for Duplicate Email'].json;

return {
  tracking: {
    successful_users: [],
    failed_rows: [],
    existing_users: [{
      email,
      full_name,
      reason: 'already_exists',
      existing_user_id: existingUser.id || null,
      timestamp: new Date().toISOString()
    }],
    total_processed: 1
  }
};

const currentRow = $node["Loop Over Items"].json;
const errors = $node["Validate Required Fields"].json.errors || [];

const failedEntry = {
  email: currentRow.email || 'unknown',
  full_name: currentRow.full_name || 'unknown',
  errors: errors,
  reason: 'validation_failed',
  timestamp: new Date().toISOString()
};

return {
  tracking: {
    successful_users: [],
    failed_rows: [failedEntry],
    existing_users: [],
    total_processed: 1
  }
};

// Collect tracking from all branches that ran
const allItems = $input.all();

let successful_users = [];
let failed_rows = [];
let existing_users = [];
let total_processed = 0;
let start_time = $node["Initialize Tracking"].json.tracking.start_time;

// Each item coming in is a completed loop iteration's tracking state
for (const item of allItems) {
  const t = item.json.tracking;
  if (!t) continue;
  successful_users = successful_users.concat(t.successful_users || []);
  failed_rows = failed_rows.concat(t.failed_rows || []);
  existing_users = existing_users.concat(t.existing_users || []);
  total_processed += t.total_processed || 0;
}

const endTime = new Date();
const startTime = new Date(start_time);
const durationMinutes = ((endTime - startTime) / 1000 / 60).toFixed(1);

const successRate = total_processed > 0
  ? ((successful_users.length / total_processed) * 100).toFixed(1)
  : '0.0';

return {
  tracking: { successful_users, failed_rows, existing_users, total_processed },
  summary: {
    successful: successful_users.length,
    failed: failed_rows.length,
    existing: existing_users.length,
    total_processed,
    duration_minutes: durationMinutes,
    success_rate: `${successRate}%`,
    completed_at: endTime.toISOString()
  }
};

const summary = $input.first().json.summary;
const tracking = $input.first().json.tracking;  

const successList = tracking.successful_users.length > 0
  ? tracking.successful_users.map(u => `  ✓ ${u.email}`).join('\n')
  : '  None';

const failedList = tracking.failed_rows.length > 0
  ? tracking.failed_rows.map(f =>
      `  ❌ ${f.email} → ${f.errors.join(', ')}`
    ).join('\n')
  : '  None';

const existingList = tracking.existing_users.length > 0
  ? tracking.existing_users.map(e =>
      `  ⚠️ ${e.email} → already exists`
    ).join('\n')
  : '  None';

const report = `
ONBOARDING IMPORT SUMMARY
=========================
📊 Total Processed : ${summary.total_processed}
✅ Created         : ${summary.successful}
⚠️  Already Existed : ${summary.existing}
❌ Failed          : ${summary.failed}
📈 Success Rate    : ${summary.success_rate}
⏱️  Duration        : ${summary.duration_minutes} mins
🕐 Completed At    : ${summary.completed_at}

CREATED USERS:
${successList}

SKIPPED (EXISTING):
${existingList}

FAILED ROWS:
${failedList}
`;

return { report, summary };

const successfulUsers = $node["Initialize Tracking"].json.successful_users || [];
const failedRows = $node["Initialize Tracking"].json.failed_rows || [];

const report = `
ONBOARDING IMPORT SUMMARY

✅ Successfully Created: ${successfulUsers.length}
❌ Errors: ${failedRows.length}

Created Users:
${successfulUsers.map(u => `✓ ${u.email}`).join('\n')}

Errors:
${failedRows.map(f => `❌ ${f.error}`).join('\n')}
`;

return { report };

const email = $node['Normalize Email & Name'].json.email;
const full_name = $node['Normalize Email & Name'].json.full_name;
const temp_password = $node['Generate Temp Password'].json.temp_password;

// Build a self-contained tracking snapshot for THIS row only
// Calculate Final Metrics will merge all snapshots together
return {
  tracking: {
    successful_users: [{ email, full_name, timestamp: new Date().toISOString() }],
    failed_rows: [],
    existing_users: [],
    total_processed: 1
  },
  temp_password
};
